%[text] # 배열 행렬 만들기
%[text] 이름: 장효준
%[text] - 벡터와 행렬을 만드는 방법
%[text] - 행렬 연산
%[text] - 행렬의 일부
%[text] - 그래프
%[text] - 소리 파일 다루기 \
%%
%[text] ## 간단한 배열
%[text] - 벡터: 열벡터, 행벡터
%[text] - 행렬: 2차원 배열 \
m = [1 4 2 5] %행 벡터, row vector %[output:1b2f7825]
v = [1; 6; -1; 3] %열 벡터, column vector %[output:8fead26d]
M = [1 3 5; 2 4 6] %[output:2ae5c9fd]
m = M(2, 2) %[output:4c7a06c4]
%%
%[text] ## 행렬의 크기
%[text] - 명령어:size, length, numel \
M %[output:761b2027]
whos M %[output:8ed34b7b]
[nRows, nCols] = size(M) %[output:5eee7fd6] %[output:18486bfc]
nn = size(M, 2) %[output:7beeba9f]
%%
%[text] ## 그래프
%[text] - 명령어: plot, stem, bar \
v %[output:453b0a9f]
h = plot(v, 'r--o', "MarkerFaceColor","r") %[output:5044e95f] %[output:7b32daa4]
h.LineWidth = 2; %[output:7b32daa4]
grid on; %[output:7b32daa4]
xlabel("$x$","Interpreter","latex"); ylabel("y") %[output:7b32daa4]
%[text] 
%%
%[text] stem 그래프
stem(v, 'r', 'filled'); %[output:7926d6a3]
grid; %[output:7926d6a3]
xlabel("value"); ylabel("measured") %[output:7926d6a3]
%%
%[text] bar 막대그래프
bar(v, "FaceColor","g") %[output:3490df84]
legend("Income") %[output:3490df84]
%%
%[text] ## 복소수 배열/ Complex Arrays
%[text] - 허수/imaginary number
%[text] - \\$i = \\sqrt{-1} \
a = 2i + 1 %[output:593f21df]
aR = real(a), aImag = imag(a) %[output:9379c72f] %[output:1e0913a3]
b = [1 2i 2+1i -1] %[output:2415ae9f]
b1 = b(1), b2 = b(2) %[output:2eb60554] %[output:2fe1fcb2]
b2 = b.^2 %[output:860b5e48]
%%
%[text] ## Array Addressing
v = 10:-2:0 %[output:309c950f]
v(1:2), v(end-1:end) %[output:896da188] %[output:09f68dd6]
v(1:2:end) %[output:838ed23b]
u = v([2 4 1 3 6 5]) %[output:88d903ef]
M = magic(5) %[output:420fd9c3]
m = M(end, :) %[output:6dfb6f0a]
w = M(:, 3) %[output:586cd6b5]
d = M(4:5, [2 4]) %[output:350de702]
v %[output:45abf4b4]
v(10) = 8 %[output:84b282f7]
%%
%[text] ### 배열을 만드는 또 다른 방법
q = (9:-2:3) + 1 %[output:2562d1ff]
r = linspace(0,10,6) %[output:2b475523]
g = logspace(0, 4, 5) %[output:715aa278]
b = 0:4, z = 2.^b %[output:36c42afb] %[output:6643ac50]
%%
%[text] ## 특별한 행렬
%[text] - zeros, ones, magic, eye \
U = zeros(3) + pi %[output:16416816]
Y = ones(2)*3 %[output:9cdc382e]
M = magic(6) %[output:4a612cd9]
dm = diag(diag(M)) %[output:4bbaddbd]
E = eye(3)*4 %[output:1e7cef39]

E2 = E^2 %[output:574f40bc]
peaks %[output:0b3aad63] %[output:3eb3a450]
%[text] 

